import { ChangeDetectorRef, Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { permissionsLabels } from 'src/app/shared/models/fmosNewRolePermissions';
import { AddSystemService } from 'src/app/shared/services/add-system.service';
import { RoleService } from 'src/app/shared/services/role.service';
import { RuleService } from 'src/app/shared/services/rule.service';

@Component({
  selector: 'npr-rule-mapping',
  templateUrl: './rule-mapping.component.html',
  styleUrls: ['./rule-mapping.component.scss'],
})
export class RuleMappingComponent implements OnInit {
  dtTrigger: any = new Subject();
  dtOptions: DataTables.Settings = {};
  ruleMappingListResp: any = [];
  isLoading: boolean = false;
  roleCodes = new permissionsLabels();
  statusArr: String[] = ['Authorized', 'Unauthorized', 'Open', 'Close'];

  constructor(
    private rulelist: RuleService,
    private roleService: RoleService,
    private router: Router,
    private addSystem: AddSystemService,
    private cdr: ChangeDetectorRef
  ) {}

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength: 5,
      columnDefs: [{ type: 'date', targets: [4] }],
      order: [[4, 'desc']],
      processing: true,
      lengthMenu: [
        [5, 10, 20, -1],
        [5, 10, 20, 30],
      ],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],
    };

    this.fetchinglistRuleMapping();
    this.roleService.fetchScreenPermissions('Rule Mapping');
    this.roleService.screenLabelList.subscribe(
      (message) => (this.roleCodes = message)
    );
    console.log(this.roleCodes);
  }

  fetchinglistRuleMapping() {
    this.isLoading = true;
    this.rulelist.fetchingruleMapping().subscribe((resp: any) => {
      for (let item of resp.result) {
        item.recordStatus = this.statusArr.find((i) =>
          i.startsWith(item.recordStatus)
        );
      }
      console.log(resp);
      this.ruleMappingListResp = resp.result;
      this.isLoading = false;
      this.cdr.markForCheck();

      this.dtTrigger.next();
    });
  }

  getById(data) {
    console.log('OnClick', data);
    let id: any = 0;
    if (data.msgMappingDetails.length > 0) {
      id = data.msgMappingDetails[0].messageMappingId;
    }

    this.rulelist.getruleMappingById(id, data.mappingId).subscribe((resp) => {
      console.log(resp);
      let queryParams = {
        sourceTransDetId: resp.sourceTransDetId,
        targetTransDetId: resp.targetTransDetId,
        mdmtMessageMappingDet: resp.mdmtMessageMappingDet,
        responseData: data,
      };
      console.log(queryParams);
      this.addSystem.sendNavParam(queryParams);
      this.router.navigate(['/rule-mapping/edit', data.mappingId]);
    });
  }

  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }
}
